SELECT COUNT(holiday_name) AS public_holiday_count
FROM holidays
WHERE holiday_date LIKE '2022%' AND is_public = 1;

SELECT holiday_name
FROM holidays
WHERE is_public = 1 AND CAST(SUBSTR(holiday_date, 1, 4) AS INTEGER) = 2022;

SELECT day_of_week
FROM dates
WHERE month = 4 AND year = 2022;

SELECT COUNT(*) 
FROM dates 
WHERE year = 2022 AND month = 4 AND is_weekend = 0;

SELECT fulldate
FROM dates
WHERE date_id = 1;

SELECT day_of_week
FROM dates
WHERE date_id = 1;

SELECT COUNT(date_id) AS monday_count
FROM dates
WHERE day_of_week = 'Monday' AND month = 4;

SELECT COUNT(date_id) AS date_count
FROM date_calendars
WHERE calendar_id = 1;

SELECT metadata_value
FROM calendar_metadata
WHERE metadata_key = 'calendar_type' AND metadata_value = 'Fiscal';

SELECT date_id, fulldate
FROM dates
WHERE year = 2022 AND day_of_week > 4;
